{
    showAddModal: false,
    showFolderModal: false,
    showViewModal: false,
    selectedAsset: null,
    currentFolder: JSON.parse('{\u0022id\u0022:\u0022a0d655fb-76d8-49b6-b4b5-1d6d86798fb1\u0022,\u0022parent_id\u0022:null,\u0022tenant_id\u0022:\u0022a0c8d839-0793-4850-9e9e-b20069a27eab\u0022,\u0022user_id\u0022:\u0022a0c8d839-6d7f-46b2-a485-1f127d60f3e7\u0022,\u0022title\u0022:\u0022Flowhive Main Folder\u0022,\u0022type\u0022:\u0022folder\u0022,\u0022category\u0022:\u0022Uncategorized\u0022,\u0022content\u0022:\u0022Folder Container\u0022,\u0022source_url\u0022:null,\u0022metadata\u0022:null,\u0022created_at\u0022:\u00222026-01-14T20:57:39.000000Z\u0022,\u0022updated_at\u0022:\u00222026-01-14T20:57:39.000000Z\u0022}'),

    // New Asset Form
    newAsset: {
        title: '',
        type: 'text',
        category: 'Market Intelligence',
        content: '',
        source_url: ''
    },
    newFolderTitle: '',
    isSaving: false,

    createFolder() {
        if (!this.newFolderTitle) return;
        this.isSaving = true;
        const formData = new FormData();
        formData.append('title', this.newFolderTitle);
        formData.append('type', 'folder');
        if (this.currentFolder) formData.append('parent_id', this.currentFolder.id);

        fetch('http://localhost:8000/knowledge-base', {
            method: 'POST',
            headers: { 'X-CSRF-TOKEN': '0STuobKwZ1NBvrW3fqaqcLq1fjaXmIvYX2TqeQS3', 'Accept': 'application/json' },
            body: formData
        })
        .then(res => res.json())
        .then(data => {
            if(data.success) window.location.reload();
            else this.isSaving = false;
        });
    },

    saveAsset() {
        if (!this.newAsset.title) {
            alert('Title is mandatory.');
            return;
        }
        this.isSaving = true;
        const formData = new FormData();
        formData.append('title', this.newAsset.title);
        formData.append('type', this.newAsset.type);
        formData.append('category', this.newAsset.category);
        formData.append('content', this.newAsset.content || '');
        if (this.newAsset.source_url) formData.append('source_url', this.newAsset.source_url);
        if (this.currentFolder) formData.append('parent_id', this.currentFolder.id);

        if (this.$refs.fileInput && this.$refs.fileInput.files.length) {
            formData.append('file', this.$refs.fileInput.files[0]);
        }

        fetch('http://localhost:8000/knowledge-base', {
            method: 'POST',
            headers: {
                'X-CSRF-TOKEN': '0STuobKwZ1NBvrW3fqaqcLq1fjaXmIvYX2TqeQS3',
                'Accept': 'application/json'
            },
            body: formData
        })
        .then(res => res.json())
        .then(data => {
            if (data.success) {
                window.location.reload();
            } else {
                alert('Save failed.');
                this.isSaving = false;
            }
        })
        .catch(err => {
            console.error(err);
            this.isSaving = false;
        });
    },

    deleteAsset(id) {
        if (!confirm('Are you sure you want to delete this asset? This cannot be undone.')) return;

        fetch(`/knowledge-base/${id}`, {
            method: 'DELETE',
            headers: { 
                'X-CSRF-TOKEN': '0STuobKwZ1NBvrW3fqaqcLq1fjaXmIvYX2TqeQS3',
                'Accept': 'application/json'
            }
        })
        .then(res => res.json())
        .then(data => {
            if (data.success) window.location.reload();
            else alert('Delete failed.');
        });
    }
}
